using System.ComponentModel;
using Microsoft.Extensions.AI;

// ── Tool state ──────────────────────────────────────────────────────────────
var notebook = new Notebook();

// ── Tool definitions ────────────────────────────────────────────────────────
var searchWeb = AIFunctionFactory.Create(
    ([Description("The search query")] string query) =>
    {
        Console.WriteLine($"  🔍  Searching the web: \"{query}\"");

        // In a real app, call Bing / Google / Brave Search API here.
        // Returning simulated snippets so the agent can still demonstrate
        // its multi-step research workflow without a live API key.
        return
            $"[Web results for \"{query}\"]\n" +
            $"1. \"{query}\" – Wikipedia overview: provides foundational definitions and history.\n" +
            $"2. Recent 2026 industry report on \"{query}\": highlights trends, adoption rates, and key statistics.\n" +
            $"3. Academic survey paper on \"{query}\": discusses benefits, limitations, and open research questions.";
    },
    "search_web",
    "Searches the web for the given query and returns relevant result snippets.");

var addNote = AIFunctionFactory.Create(
    ([Description("A concise note capturing a key finding")] string note) =>
    {
        notebook.Add(note);
        Console.WriteLine($"  📝  Note saved ({notebook.Count} total)");
        return $"Note saved. You have {notebook.Count} note(s).";
    },
    "add_note",
    "Saves a research note. Use this to record important findings during research.");

var readNotes = AIFunctionFactory.Create(
    () =>
    {
        if (notebook.Count == 0)
            return "No notes recorded yet.";
        return string.Join('\n', notebook.Notes.Select((n, i) => $"{i + 1}. {n}"));
    },
    "read_notes",
    "Returns all research notes saved so far.");

// ── Chat client with automatic tool invocation ──────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

IChatClient client = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey)
            .GetChatClient("gpt-4o-mini")
            .AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Agent prompt ────────────────────────────────────────────────────────────
var topic = args.Length > 0
    ? string.Join(' ', args)
    : "the impact of large language models on software engineering";

Console.WriteLine($"Research Agent Starting...\nTopic: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the
        user's topic and produce a well-structured summary.

        Workflow:
        1. Use search_web 2-3 times with varied queries to gather broad info.
        2. After each search, call add_note to record the key findings.
        3. When done searching, call read_notes to review all your notes.
        4. Write a final, well-organized summary with sections and bullet
           points, citing the queries you used.
        """),
    new(ChatRole.User, $"Research the following topic and provide a summary:\n{topic}")
];

var options = new ChatOptions
{
    Tools = [searchWeb, addNote, readNotes]
};

// ── Run the agent ───────────────────────────────────────────────────────────
var response = await client.GetResponseAsync(messages, options);

Console.WriteLine();
Console.WriteLine("══════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("══════════════════════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);

// ── Helpers ─────────────────────────────────────────────────────────────────
class Notebook
{
    private readonly List<string> _notes = [];
    public int Count => _notes.Count;
    public IReadOnlyList<string> Notes => _notes;
    public void Add(string note) => _notes.Add(note);
}

